rule-obj-flow.pageList:
{% for shape in shapes %}

  {{ shape.type }}
  {{ shape.name }}
  {{ shape.label | default(shape.name) }}
  {% if shape.type == "Assignment" %}
  {{ shape.flow_action | default('') }}
  {{ shape.route_type | default('Operator') }}
  {{ shape.route_to | default('') }}
  {% endif %}
  {% if shape.type == "Decision" %}
  {{ shape.decision_type | default('Condition') }}
  {% for condition in shape.conditions | default([]) %}
  {{ condition.when }}
  {{ condition.then }}
  {% endfor %}
  {% endif %}
  {% if shape.type == "SubFlow" %}
  {{ shape.subflow_name }}
  {% endif %}
  {% if shape.type == "Connector" %}
  {{ shape.connector_type | default('Normal') }}
  {{ shape.from_shape }}
  {{ shape.to_shape }}
  {{ shape.connector_label | default('') }}
  {% endif %}

{% endfor %}

{% for connector in connectors | default([]) %}

  {{ connector.from_shape }}
  {{ connector.to_shape }}
  {{ connector.label | default('') }}
  {{ connector.condition | default('') }}

{% endfor %}
